body.script:
let ws;
let digits = [];
let running = false;
let stake = 1;
let app_id = 1089; // public test app id

function log(msg) {
  document.getElementById("log").innerHTML = msg + "
" + document.getElementById("log").innerHTML;
}

function startBot() {
  running = true;
  ws = new WebSocket("wss://ws.derivws.com/websockets/v3?app_id=" + app_id);

  ws.onopen = () => {
    log("Connected...");
    subscribeTicks();
  };

  ws.onmessage = (msg) => {
    let data = JSON.parse(msg.data);

    if (data.tick) {
      let digit = parseInt(data.tick.quote.toString().slice(-1));
      digits.push(digit);

      if (digits.length > 50) digits.shift();

      analyze();
    }
  };
}

function stopBot() {
  running = false;
  if (ws) ws.close();
  log("Bot stopped.");
}

function subscribeTicks() {
  ws.send(JSON.stringify({
    ticks: "R_100",
    subscribe: 1
  }));
}

function analyze() {
  if (!running || digits.length < 20) return;

  let freq = Array(10).fill(0);

  digits.forEach(d => freq[d]++);

  let total = digits.length;
  let probs = freq.map(f => (f / total) * 100);

  let sorted = probs
    .map((p, i) => ({ digit: i, prob: p }))
    .sort((a, b) => b.prob - a.prob);

  let highest = sorted[0];
  let second = sorted[1];

  log(`Top: ${highest.digit} (${highest.prob.toFixed(2)}%) | Entry: ${second.digit}`);

  // ENTRY CONDITION
  let lastDigit = digits[digits.length - 1];

  if (lastDigit === second.digit) {
    placeTrade(highest.digit);
  }
}

function placeTrade(digit) {
  log("Placing trade for digit: " + digit);

  ws.send(JSON.stringify({
    proposal: 1,
    amount: stake,
    basis: "stake",
    contract_type: "DIGITMATCH",
    currency: "USD",
    duration: 2,
    duration_unit: "t",
    symbol: "R_100",
    barrier: digit.toString()
  }));

  ws.onmessage = (msg) => {
    let data = JSON.parse(msg.data);

    if (data.proposal) {
      ws.send(JSON.stringify({
        buy: data.proposal.id,
        price: stake
      }));
      log("Trade executed!");
    }

    if (data.tick) {
      let digit = parseInt(data.tick.quote.toString().slice(-1));
      digits.push(digit);
      if (digits.length > 50) digits.shift();
      analyze();
    }
  };
}
